"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextValue = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  orientation?: "horizontal" | "vertical"
  activeStep: number
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()
  const state: "completed" | "active" | "pending" =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn("flex items-center", className)}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const itemContext = React.useContext(StepperItemContext)
  if (!itemContext) {
    throw new Error("StepperTrigger must be used within a <StepperItem />")
  }
  const { step, state } = itemContext

  return (
    <button
      data-slot="stepper-trigger"
      type="button"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium",
        "transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" && "border-primary bg-background text-primary",
        state === "pending" &&
          "border-muted-foreground/40 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-muted-foreground text-sm", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const itemContext = React.useContext(StepperItemContext)
  const isCompleted = itemContext?.state === "completed"

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "flex-1 transition-colors",
        orientation === "horizontal" ? "h-px min-w-4" : "w-px min-h-8",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn(className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
